"use client";
import { useState } from "react";
import { DataTable, type DataTableColumn } from "@/components/ui/data-table";

interface Order {
  id: string;
  order: string;
  customer: string;
  total: number;
}

const data: Order[] = Array.from({ length: 40 }, (_, i) => ({
  id: `ord-${i}`,
  order: `#${1000 + i}`,
  customer: ["Alex", "Sara", "Jordan", "Maya"][i % 4],
  total: (i + 1) * 19.5,
}));

const columns: DataTableColumn<Order>[] = [
  { id: "order", header: "Order", accessor: (row) => row.order },
  { id: "customer", header: "Customer", accessor: (row) => row.customer },
  { id: "total", header: "Total", accessor: (row) => row.total, cell: (row) => `$${row.total.toFixed(2)}`, align: "right" },
];

export default function Orders() {
  const [selected, setSelected] = useState<string[]>([]);
  return (
    <DataTable
      data={data}
      columns={columns}
      getRowId={(row) => row.id}
      preset="advanced"
      selectedIds={selected}
      onSelectionChange={setSelected}
      renderExpanded={(row) => <div>Details for {row.order}</div>}
      theme="dark"
    />
  );
}

